⟨u, v⟩ = u₁v₁ + u₂v₂ + ... + uₙvₙ

// Notações equivalentes: u·v ou uᵀv

// Propriedades:
⟨u, v⟩ = ⟨v, u⟩              (simetria)
⟨αu+βv, w⟩ = α⟨u,w⟩+β⟨v,w⟩  (linearidade)
⟨u, u⟩ ≥ 0, com = 0 ⟺ u=0   (positividade)

// Norma via produto interno:
‖u‖ = √⟨u, u⟩

cos θ = ⟨u, v⟩ / (‖u‖ · ‖v‖)

Desigualdade de Cauchy-Schwarz:
|⟨u, v⟩| ≤ ‖u‖ · ‖v‖

// A igualdade vale ⟺ u e v são paralelos

// Desigualdade Triangular:
‖u + v‖ ≤ ‖u‖ + ‖v‖

W⊥ = { v ∈ Rⁿ | ⟨v, w⟩ = 0 para todo w ∈ W }

Propriedades:
  dim(W) + dim(W⊥) = n
  (W⊥)⊥ = W
  W ∩ W⊥ = {0}

// Exemplos:
// W = eixo x em R²  →  W⊥ = eixo y
// W = plano xy em R³ → W⊥ = eixo z
